func solve(landStartTime []int64, landDuration []int64, waterStartTime []int64, waterDuration []int64) int64 {
	// Calculate all possible end times for land and water attractions
	var landEndTimes []int64
	var waterEndTimes []int64

	// Calculate end times for land attractions
	for i := 0; i < len(landStartTime); i++ {
		// The land attraction can start at its earliest time or later
		// We choose the earliest possible start time to minimize the end time
		landEndTimes = append(landEndTimes, landStartTime[i]+landDuration[i])
	}

	// Calculate end times for water attractions
	for j := 0; j < len(waterStartTime); j++ {
		// The water attraction can start at its earliest time or later
		// We choose the earliest possible start time to minimize the end time
		waterEndTimes = append(waterEndTimes, waterStartTime[j]+waterDuration[j])
	}

	// Initialize the minimum possible end time
	var minEndTime int64 = 1<<63 - 1

	// Try all combinations of land and water attractions
	for _, landEnd := range landEndTimes {
		for _, waterEnd := range waterEndTimes {
			// If the water attraction starts after the land attraction ends, the end time is waterEnd
			// If the land attraction starts after the water attraction ends, the end time is landEnd
			// If they overlap, the end time is the maximum of the two end times
			endTime := int64(0)
			if waterEnd > landEnd {
				endTime = waterEnd
			} else {
				endTime = landEnd
			}
			if endTime < minEndTime {
				minEndTime = endTime
			}
		}
	}

	return minEndTime
}
